export default function Services() {
  const sectionRef = useRef(null);
  const trackRef = useRef(null);

  useEffect(() => {
    if (typeof window === "undefined") return;
    gsap.registerPlugin(ScrollTrigger);

    const isMobile = window.matchMedia("(max-width: 767px)").matches;
    if (isMobile) return;

    const ctx = gsap.context(() => {
      const track = trackRef.current;
      if (!track) return;

      const distance = track.scrollWidth - window.innerWidth;
      gsap.to(track, {
        x: -distance,
        ease: "none",
        scrollTrigger: {
          trigger: sectionRef.current,
          pin: true,
          pinSpacing: true,
          anticipatePin: 1,
          scrub: true,
          start: "top top",
          end: () => `+=${distance}`,
          invalidateOnRefresh: true,
        },
      });

      const refresh = () => ScrollTrigger.refresh();
      refresh();
      window.addEventListener("load", refresh);
      return () => window.removeEventListener("load", refresh);
    }, sectionRef);

    return () => ctx.revert();
  }, []);

  return (
    <section
      id="servicios"
      ref={sectionRef}
      className="relative bg-paper md:overflow-hidden"
    >
      <div className="md:h-screen md:flex md:flex-col">
        <Container className="pt-16 md:pt-28 pb-2">
          <div className="grid grid-cols-12 gap-x-4 md:gap-x-8 gap-y-6 items-end">
            <div className="col-span-12 md:col-span-7 space-y-3">
              <p className="text-[10px] uppercase tracking-[0.24em] text-inkSoft">· Servicios</p>
              <h2 className="font-display font-medium text-3xl md:text-4xl text-balance leading-tight tracking-tighter">
                Todo lo que necesita tu operativa,
                <span className="italic text-wood"> en un solo proveedor.</span>
              </h2>
            </div>
            <p className="col-span-12 md:col-span-4 md:col-start-9 text-sm text-inkSoft text-pretty">
              Cinco servicios coordinados desde Sentmenat. Desliza para
              recorrerlos.
            </p>
          </div>
        </Container>

        <div className="md:flex-1 md:flex md:items-center md:overflow-hidden md:pb-[2vh] pb-16">
          <div
            ref={trackRef}
            className="flex flex-col md:flex-row gap-6 md:gap-8 px-section-x md:px-0 md:pl-section-x md:pr-section-x md:h-[64vh] will-change-transform"
          >
            {items.map((it) => (
              <article
                key={it.n}
                className="relative shrink-0 w-full md:w-[72vw] lg:w-[58vw] md:h-full bg-paperSoft border border-border flex flex-col md:grid md:grid-cols-2"
              >
                {it.featured && <StarSticker />}

                <div className="relative bg-paperDeep min-h-[220px] md:min-h-0 overflow-hidden">
                  <StockImg src={it.img} alt={it.alt} w={1400} />
                </div>

                <div className="p-6 md:p-10 flex flex-col gap-5 overflow-y-auto">
                  <div className="flex items-center justify-between">
                    <span className="font-mono text-xs tracking-widest text-inkSoft">{it.n}</span>
                  </div>

                  <h3 className="font-display font-medium text-2xl md:text-3xl leading-[1.05] tracking-tighter text-balance">
                    {it.title}
                  </h3>

                  <p className="text-sm md:text-base text-inkSoft text-pretty leading-[1.4]">
                    {it.body}
                  </p>

                  <ul className="grid grid-cols-1 sm:grid-cols-2 gap-y-2 gap-x-4 border-t border-border pt-4 text-sm text-ink">
                    {it.tags.map((t) => (
                      <li key={t} className="flex items-start gap-2.5 leading-[1.25]">
                        <BoxIcon />
                        {t}
                      </li>
                    ))}
                  </ul>

                  {it.closer && (
                    <p className="font-display italic text-base md:text-lg text-wood text-pretty leading-[1.25] mt-auto pt-4">
                      {it.closer}
                    </p>
                  )}
                </div>
              </article>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}
